import { initializeApp } from 'firebase/app';
import { getAuth, signInWithPopup, GoogleAuthProvider, FacebookAuthProvider, OAuthProvider, createUserWithEmailAndPassword, signInWithEmailAndPassword, onAuthStateChanged, User, sendPasswordResetEmail } from 'firebase/auth';
import { getFirestore, doc, getDocFromServer } from 'firebase/firestore';
import firebaseConfig from '../../firebase-applet-config.json';

const app = initializeApp(firebaseConfig);
// Using firestoreDatabaseId generated by set_up_firebase if it exists, otherwise use default
export const db = (firebaseConfig as any).firestoreDatabaseId 
  ? getFirestore(app, (firebaseConfig as any).firestoreDatabaseId)
  : getFirestore(app);
export const auth = getAuth(app);

const googleProvider = new GoogleAuthProvider();
const facebookProvider = new FacebookAuthProvider();
const yahooProvider = new OAuthProvider('yahoo.com');

// Request Workspace scopes explicitly requested by user (and standard profile)
googleProvider.addScope('https://www.googleapis.com/auth/spreadsheets');
googleProvider.addScope('https://www.googleapis.com/auth/gmail.send');
googleProvider.addScope('email');

let isSigningIn = false;
let cachedAccessToken: string | null = null;

export const initAuth = (
  onAuthSuccess?: (user: User, token: string | null) => void,
  onAuthFailure?: () => void
) => {
  return onAuthStateChanged(auth, async (user: User | null) => {
    if (user) {
      if (cachedAccessToken || !isSigningIn) {
        if (onAuthSuccess) onAuthSuccess(user, cachedAccessToken);
      }
    } else {
      cachedAccessToken = null;
      if (onAuthFailure) onAuthFailure();
    }
  });
};

export const googleSignIn = async (): Promise<{ user: User; accessToken: string } | null> => {
  try {
    isSigningIn = true;
    const result = await signInWithPopup(auth, googleProvider);
    const credential = GoogleAuthProvider.credentialFromResult(result);
    
    if (credential?.accessToken) {
      cachedAccessToken = credential.accessToken;
    }
    
    return { user: result.user, accessToken: cachedAccessToken || '' };
  } catch (error: any) {
    console.error('Sign in error:', error);
    throw error;
  } finally {
    isSigningIn = false;
  }
};

export const facebookSignIn = async () => {
  try {
    isSigningIn = true;
    const result = await signInWithPopup(auth, facebookProvider);
    return result;
  } catch (error: any) {
    console.error('Facebook Sign in error:', error);
    throw error;
  } finally {
    isSigningIn = false;
  }
};

export const yahooSignIn = async () => {
  try {
    isSigningIn = true;
    const result = await signInWithPopup(auth, yahooProvider);
    return result;
  } catch (error: any) {
    console.error('Yahoo Sign in error:', error);
    throw error;
  } finally {
    isSigningIn = false;
  }
};

export const registerWithEmail = async (email: string, pass: string) => {
  try {
    isSigningIn = true;
    return await createUserWithEmailAndPassword(auth, email, pass);
  } catch (error: any) {
    console.error('Registration error:', error);
    throw error;
  } finally {
    isSigningIn = false;
  }
};

export const loginWithEmail = async (email: string, pass: string) => {
  try {
    isSigningIn = true;
    return await signInWithEmailAndPassword(auth, email, pass);
  } catch (error: any) {
    console.error('Login error:', error);
    throw error;
  } finally {
    isSigningIn = false;
  }
};

export const resetPassword = async (email: string) => {
  return await sendPasswordResetEmail(auth, email);
};

export const getAccessToken = async (): Promise<string | null> => {
  return cachedAccessToken;
};

export const logout = async () => {
  await auth.signOut();
  cachedAccessToken = null;
};

// Validate connection on boot
async function testConnection() {
  try {
    await getDocFromServer(doc(db, 'test', 'connection'));
  } catch (error) {
    if (error instanceof Error && error.message.includes('the client is offline')) {
      console.error("Please check your Firebase configuration.");
    }
  }
}
testConnection();
